.mutation(async ({ ctx, input }) => {
  if (!isOptInFeature(input.slug)) {
    throw new TRPCError({
      code: "BAD_REQUEST",
      message: "Invalid slug. This feature is not opt-in configurable.",
    });
  }

  if (!isFeatureAllowedForScope(input.slug, "user")) {
    throw new TRPCError({
      code: "BAD_REQUEST",
      message: `Feature "${input.slug}" is not available at the user scope`,
    });
  }

  if (input.state === "inherit") {
    await featureOptInService.setUserFeatureState({
      userId: ctx.user.id,
      featureId: input.slug,
      state: input.state,
    });
  } else {
    await featureOptInService.setUserFeatureState({
      userId: ctx.user.id,
      featureId: input.slug,
      state: input.state,
      assignedBy: ctx.user.id,
    });
  }

  return { success: true };
}),

